const body = $input.first().json.body || {};
const event = body.event || {};

if (body.type === 'url_verification') return [];
if (event.bot_id || event.subtype === 'bot_message') return [];
if (event.channel !== 'C0AM2310P8A') return [];

const text = (event.text || '').toLowerCase();
if (!text.includes('log this') && !text.includes('decided:')) return [];

return [{
  json: {
    channel: event.channel,
    thread_ts: event.thread_ts || event.ts,
    ts: event.ts,
    user: event.user || '',
    text: event.text || ''
  }
}];

const thread = $('Fetch Thread History').first().json.messages || [];
const trigger = $('Filter Decision Messages').first().json;
const knowledgeBase64 = $('Fetch KNOWLEDGE.md').first().json.content || '';
const knowledge = Buffer.from(knowledgeBase64, 'base64').toString('utf8');

const matches = [...knowledge.matchAll(/### D(\d+)/g)].map((m) => Number(m[1])).filter((n) => Number.isFinite(n));
const next = (matches.length ? Math.max(...matches) : 0) + 1;
const entryNumber = `D${next}`;

const decisionText = (thread[thread.length - 1]?.text || trigger.text || 'Decision captured in Slack').replace(/\s+/g, ' ').trim();
const shortTitle = decisionText.replace(/^(log this:|decided:)\s*/i, '').slice(0, 72) || 'Slack Decision';
const date = new Date().toISOString().slice(0, 10);

const formattedEntry = `### ${entryNumber} — ${shortTitle} (${date})\n**Context**: Decision captured from #decisions Slack thread.\n**Decision**: ${decisionText}\n**Alternatives**: Not explicitly documented in thread.\n**Reversibility**: Medium`;

return [{ json: { entry_number: entryNumber, title: shortTitle, formatted_entry: formattedEntry } }];

const knowledgeResponse = $('Fetch KNOWLEDGE.md').first().json;
const currentContentBase64 = knowledgeResponse.content || '';
const sha = knowledgeResponse.sha;

const currentContent = Buffer.from(currentContentBase64, 'base64').toString('utf8');

const aiResponse = $('Format Decision').first().json;
const formattedEntry = aiResponse.formatted_entry;
const entryNumber = aiResponse.entry_number;
const title = aiResponse.title;

const updatedContent = currentContent.trimEnd() + '\n\n' + formattedEntry + '\n';
const updatedBase64 = Buffer.from(updatedContent, 'utf8').toString('base64');

return [{
  json: {
    content: updatedBase64,
    sha: sha,
    message: `docs: log ${entryNumber} — ${title}`,
    entry_number: entryNumber,
    title: title
  }
}];
